{
  "extends": ["config:base"],
  "packageRules": [
    {
      "description": "Tier 1 — auto-merge patch upgrades within approved range",
      "matchPackageNames": ["openai", "anthropic", "boto3", "google-generativeai"],
      "matchUpdateTypes": ["patch"],
      "automerge": true,
      "automergeType": "pr",
      "requiredStatusChecks": [
        "dependency-policy",
        "eval-suite",
        "security-scan",
        "build"
      ]
    },
    {
      "description": "Tier 1 — notify on minor/major, require manual RFC update",
      "matchPackageNames": ["openai", "anthropic", "boto3", "google-generativeai"],
      "matchUpdateTypes": ["minor", "major"],
      "automerge": false,
      "labels": ["dep-upgrade", "tier-1", "requires-rfc-update"]
    },
    {
      "description": "Tier 2 — batch monthly, require eval gate and allowlist update",
      "matchPackageNames": ["langchain-core", "llama-index-core", "semantic-kernel"],
      "schedule": ["on the first day of the month"],
      "automerge": false,
      "labels": ["dep-upgrade", "tier-2", "requires-eval"]
    },
    {
      "description": "Tier 3 — batch quarterly",
      "matchPackageNames": ["tiktoken", "instructor", "pydantic-ai", "guidance"],
      "schedule": ["on the first day of the month in January, April, July, October"],
      "automerge": false,
      "labels": ["dep-upgrade", "tier-3", "quarterly-review"]
    }
  ]
}

{
  "freeze": {
    "start": "2025-12-15",
    "end": "2026-01-06",
    "reason": "Holiday period — reduced on-call staffing",
    "exceptions": ["CRITICAL CVE patches require CISO approval to proceed during freeze"]
  }
}
